1	// claim-office.ts
2	//
3	// Design choices for the input shape (documented for future tests):
4	// - quote(input) takes an object with `customer` and `items`.
5	//   - customer: { yearsWithMHPCO: number, isFollowUpContract: boolean }
6	//     - yearsWithMHPCO: how long the customer has been with MHPCO (drives loyalty discount).
7	//     - isFollowUpContract: whether this quote is the customer's second/follow-up
8	//       contract in the scenario (drives the 15% follow-up discount).
9	//   - items: an array of items to be insured. Empty array means no items.
10	// - quote returns the premium in G as a number.
11	// - claim is also exported (per the spec import) but not yet implemented.
12	
13	export type Customer = {
14	  yearsWithMHPCO: number;
15	  isFollowUpContract: boolean;
16	};
17	
18	export type Item = {
19	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
20	  cursed?: boolean;
21	  enchantment?: number;
22	};
23	
24	export type QuoteInput = {
25	  customer: Customer;
26	  items: Item[];
27	};
28	
29	// Flat fee added to every quote at the very end (spec: "processing fee of 5 G").
30	// Currently observed in the empty-list test (premium = fee only).
31	const PROCESSING_FEE = 5;
32	
33	// Block-of-3 discount: when items are exactly 3 of the same type,
34	// the policy base premium for that group is a flat 60 G.
35	const BLOCK_SIZE = 3;
36	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
37	
38	// Base premium per item type, in G (before any modifiers or fees).
39	// Keyed by Item["type"] so adding a new item variant is caught at compile time
40	// (the Record will require a corresponding entry).
41	const BASE_PREMIUM_BY_TYPE: Record<Item["type"], number> = {
42	  sword: 100,
43	  amulet: 60,
44	  staff: 80,
45	  potion: 40,
46	  rune: 25,
47	  moonstone: 25,
48	};
49	
50	// First-insurance surcharge: 10% added on top of an item's base premium.
51	// Expressed as numerator/denominator to avoid floating-point error
52	// for the integer cases currently under test (e.g. 100 * 1.1 ≠ 110 in IEEE-754).
53	function withFirstInsurance(base: number): number {
54	  return (base * 11) / 10;
55	}
56	
57	// Cursed-item surcharge: 50% added on top of the item's base premium.
58	// Same numerator/denominator style as withFirstInsurance for integer safety.
59	function withCursedSurcharge(base: number): number {
60	  return (base * 3) / 2;
61	}
62	
63	// High-enchantment surcharge: 30% added on top of the item's base premium
64	// when the item's enchantment is at least 5.
65	function withHighEnchantmentSurcharge(base: number): number {
66	  return (base * 13) / 10;
67	}
68	
69	// Component types eligible for the block-of-3 discount.
70	const COMPONENT_TYPES: ReadonlySet<Item["type"]> = new Set(["rune", "moonstone"]);
71	
72	function isComponent(item: Item): boolean {
73	  return COMPONENT_TYPES.has(item.type);
74	}
75	
76	function itemBasePremium(item: Item): number {
77	  const base = BASE_PREMIUM_BY_TYPE[item.type];
78	  let total = base;
79	  if (item.cursed) {
80	    total += (base * 1) / 2;
81	  }
82	  if (item.enchantment !== undefined && item.enchantment >= 5) {
83	    total += (base * 3) / 10;
84	  }
85	  return total;
86	}
87	
88	function groupBaseSum(items: Item[]): number {
89	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
90	}
91	
92	function groupByType(items: Item[]): Map<Item["type"], Item[]> {
93	  const groups = new Map<Item["type"], Item[]>();
94	  for (const item of items) {
95	    const group = groups.get(item.type) ?? [];
96	    group.push(item);
97	    groups.set(item.type, group);
98	  }
99	  return groups;
100	}
101	
102	function groupBasePremium(group: Item[]): number {
103	  if (group.length === BLOCK_SIZE && isComponent(group[0])) {
104	    return BLOCK_OF_THREE_BASE_PREMIUM;
105	  }
106	  return groupBaseSum(group);
107	}
108	
109	function policyBasePremium(items: Item[]): number {
110	  const groups = groupByType(items);
111	  return Array.from(groups.values()).reduce(
112	    (total, group) => total + groupBasePremium(group),
